import{_ as s,H as n,f as e,i as t}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"投机解码:用空闲算力一次推 k 个候选","description":"","frontmatter":{},"headers":[],"relativePath":"aiInfraLearning/11-投机解码.md","filePath":"aiInfraLearning/11-投机解码.md","lastUpdated":1778649484000}'),p={name:"aiInfraLearning/11-投机解码.md"};function i(l,a,o,r,d,c){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="投机解码-用空闲算力一次推-k-个候选" tabindex="-1">投机解码:用空闲算力一次推 k 个候选 <a class="header-anchor" href="#投机解码-用空闲算力一次推-k-个候选" aria-label="Permalink to &quot;投机解码:用空闲算力一次推 k 个候选&quot;">​</a></h1><p>02 篇画完 Roofline 后这件事其实已经摆在台面上了:<strong>LLM decode 阶段算力远没跑满,瓶颈在 HBM 带宽</strong>。H100 FP16 算力 989 TFLOPS,decode batch=1 时实际跑出来不到 1%——99% 的 Tensor Core 空转,只是在等权重从 HBM 搬过来。换个角度:既然把模型从 HBM 搬一遍只能产出 1 个 token 太亏,那能不能<strong>一次 forward 出多个 token</strong>?投机解码(Speculative Decoding)就是答这个问题的工程化方案。这一篇拆它的心智、四种主流流派、什么时候真加速、什么时候反而拖慢。</p><blockquote><p>一句话先记住:<strong>投机解码 = 用一个便宜的&quot;草稿器&quot;先猜 k 个 token,再用大模型一次 forward 验证,接受最长合法前缀</strong>。能加速的根因是 decode 是 memory-bound——大模型反正要被搬一遍,搬一次顺便算 k 个候选几乎不增加耗时,只要接受率够高就净赚。关键不在&quot;会不会用&quot;,在&quot;什么时候用收益正,什么时候是负优化&quot;。</p></blockquote><hr><h2 id="一、为什么这事能成立" tabindex="-1">一、为什么这事能成立 <a class="header-anchor" href="#一、为什么这事能成立" aria-label="Permalink to &quot;一、为什么这事能成立&quot;">​</a></h2><h3 id="_1-1-朴素-decode-是个浪费" tabindex="-1">1.1 朴素 decode 是个浪费 <a class="header-anchor" href="#_1-1-朴素-decode-是个浪费" aria-label="Permalink to &quot;1.1 朴素 decode 是个浪费&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>朴素 decode(每步 1 个 token):</span></span>
<span class="line"><span>   step 1:  HBM → SM (搬整个模型)  → 算一次 → 出 1 个 token</span></span>
<span class="line"><span>   step 2:  HBM → SM (搬整个模型)  → 算一次 → 出 1 个 token</span></span>
<span class="line"><span>   step 3:  HBM → SM (搬整个模型)  → 算一次 → 出 1 个 token</span></span>
<span class="line"><span>   ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每一步,几十 GB 的权重要从 HBM 流过 SM 一次,只换 1 个 token。</span></span>
<span class="line"><span>权重的&quot;使用密度&quot;极低——这就是 02 篇说的 memory-bound 本质。</span></span></code></pre></div><p>把多个候选 token 塞进同一次 forward,<strong>权重只搬一次,算出多个 logits</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>投机 decode(每步 k 个候选):</span></span>
<span class="line"><span>   step:  HBM → SM (搬整个模型)  → 一次算 k 个位置的 logits</span></span>
<span class="line"><span>                                  → 验证草稿器给的 k 个候选有几个对</span></span>
<span class="line"><span>                                  → 接受 m 个 (0 ≤ m ≤ k)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>权重还是只搬一次,但产出 m 个 token。算力增量?基本忽略</span></span>
<span class="line"><span>(decode 的 SM 利用率本来就只有 5-50%)。</span></span></code></pre></div><p><strong>净增益 = 多产出 (m-1) 个 token,代价 = 跑一次草稿器 + 一点点额外算力</strong>。只要草稿器够便宜、接受率够高,就赚。</p><h3 id="_1-2-一张图看朴素-vs-投机" tabindex="-1">1.2 一张图看朴素 vs 投机 <a class="header-anchor" href="#_1-2-一张图看朴素-vs-投机" aria-label="Permalink to &quot;1.2 一张图看朴素 vs 投机&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>朴素 decode(每步 1 个 token):</span></span>
<span class="line"><span>  ──────────────────────────────────────────────→  时间</span></span>
<span class="line"><span>   T1 │ T2 │ T3 │ T4 │ T5 │ T6 │ T7 │ T8 │ ...</span></span>
<span class="line"><span>  ←Δ→</span></span>
<span class="line"><span>  每步 Δ ≈ 一次完整 forward(memory-bound,几十毫秒)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>投机 decode(k=4,接受率 70%):</span></span>
<span class="line"><span>  ──────────────────────────────────────────────→  时间</span></span>
<span class="line"><span>   [D] T1 T2 T3 ✗  │ [D] T4 T5 T6 ✗  │ ...</span></span>
<span class="line"><span>  ←──── Δ_spec ───→</span></span>
<span class="line"><span>   D  = 草稿器 4 步(很快,小模型或并行头)</span></span>
<span class="line"><span>   T1-3 = 大模型一次 forward 验证,接受 3 个</span></span>
<span class="line"><span>   ✗  = 第 4 个被拒,从这里开始下一轮</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  每轮平均产出 3 个 token,Δ_spec 略大于 Δ(多了草稿器开销和 k 个位置的算力),</span></span>
<span class="line"><span>  但远不到 3 倍。净加速 ≈ 2-3x。</span></span></code></pre></div><p>注意:<strong>投机解码不改变最终生成的分布</strong>——通过精心设计的接受/拒绝采样(Leviathan 2023 论文证明等价于 target 模型本身的采样),输出和直接跑 target 是统计同分布的。<strong>这不是&quot;近似加速&quot;,是&quot;无损加速&quot;</strong>。</p><h3 id="_1-3-接受率-acceptance-rate-是命门" tabindex="-1">1.3 接受率(acceptance rate)是命门 <a class="header-anchor" href="#_1-3-接受率-acceptance-rate-是命门" aria-label="Permalink to &quot;1.3 接受率(acceptance rate)是命门&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设 k 为每轮草稿 token 数,α 为单 token 接受概率(假设独立)。</span></span>
<span class="line"><span>平均一轮接受 token 数:</span></span>
<span class="line"><span>    E[m] = (1 - α^(k+1)) / (1 - α)   (含贡献到下一步起点的那一个)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实际近似:E[m] ≈ k × α  (α 较低时偏低估,但量级对)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>α=0.5, k=4:  E[m] ≈ 2 → 2x 加速</span></span>
<span class="line"><span>α=0.7, k=4:  E[m] ≈ 2.8 → 2.5x 加速  </span></span>
<span class="line"><span>α=0.85, k=8: E[m] ≈ 6 → 4-5x 加速</span></span>
<span class="line"><span>α=0.3, k=4:  E[m] ≈ 1.2 → 几乎不赚,草稿开销吃掉收益</span></span></code></pre></div><p><strong>所以&quot;投机解码能不能上&quot;的全部就是问一个问题:这模型 / 这任务的接受率能到多少</strong>。代码、数学、明确指令任务接受率 70-85% 常见;开放创作、长篇 narrative 接受率可能掉到 40-50%,得不偿失。</p><hr><h2 id="二、四种流派" tabindex="-1">二、四种流派 <a class="header-anchor" href="#二、四种流派" aria-label="Permalink to &quot;二、四种流派&quot;">​</a></h2><h3 id="_2-1-speculative-decoding-原始版-独立小模型作-draft" tabindex="-1">2.1 Speculative Decoding(原始版):独立小模型作 draft <a class="header-anchor" href="#_2-1-speculative-decoding-原始版-独立小模型作-draft" aria-label="Permalink to &quot;2.1 Speculative Decoding(原始版):独立小模型作 draft&quot;">​</a></h3><p>Chen et al. 2023, Leviathan et al. 2023 同期工作。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>target:  Llama-3.1-70B   (慢但准)</span></span>
<span class="line"><span>draft:   Llama-3.2-1B    (快,可能不准)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每轮:</span></span>
<span class="line"><span>  1. draft 自回归生成 k 个候选 token: t1, t2, ..., tk</span></span>
<span class="line"><span>  2. target 一次 forward 把 [prompt + t1..tk] 全部 K/V/logits 算出</span></span>
<span class="line"><span>  3. 从前往后比对:</span></span>
<span class="line"><span>     - 若 target 在位置 i 的分布认可 t_i(基于接受/拒绝采样)→ 接受</span></span>
<span class="line"><span>     - 首个被拒的位置 j:从 target 的位置 j 分布采样一个 token 替代</span></span>
<span class="line"><span>     - 后面的 t_{j+1..k} 全部丢弃</span></span>
<span class="line"><span>  4. 接受了 m + 1 个 token(m 个 draft 接受 + 1 个 target 替代/续作)</span></span></code></pre></div><p><strong>好处</strong>:不动 target 模型,任何 HF 模型都能套。 <strong>代价</strong>:</p><ul><li>需要找一个&quot;风格相近&quot;的小模型(同家族最理想,如 Llama 70B + Llama 1B / 8B)</li><li>跨家族搭配接受率低(Qwen 当 Llama 的 draft 多半不行)</li><li>draft 模型占额外显存 + 自己也要 KV cache</li><li>draft 自回归 k 步也不便宜,k 选得不对反而慢</li></ul><p>工程上能用,但有更优秀的接替者。</p><h3 id="_2-2-medusa-不要-draft-模型-target-模型本体长几个头" tabindex="-1">2.2 Medusa:不要 draft 模型,target 模型本体长几个头 <a class="header-anchor" href="#_2-2-medusa-不要-draft-模型-target-模型本体长几个头" aria-label="Permalink to &quot;2.2 Medusa:不要 draft 模型,target 模型本体长几个头&quot;">​</a></h3><p>Cai et al. 2024。核心想法是:<strong>为什么要单独养一个小模型?在 target 模型的最后一个 hidden state 上,平行接几个&quot;投机头&quot;,每个头预测未来第 i 个位置的 token</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>target 模型最后一层 hidden state h</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>   ┌────┴──────┬──────┬──────┐</span></span>
<span class="line"><span>   ▼           ▼      ▼      ▼</span></span>
<span class="line"><span> LM Head    Medusa  Medusa  Medusa</span></span>
<span class="line"><span> (位置 0)   Head 1  Head 2  Head 3</span></span>
<span class="line"><span>            (位置+1)(位置+2)(位置+3)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>一次 forward,4 个 logits → 4 个候选 token (含位置 0 这个常规的)</span></span></code></pre></div><p><strong>好处</strong>:</p><ul><li>不需要独立模型,只在 target 上加 ~几亿参数的额外 MLP 头</li><li>一次 forward 就出 k 个候选,<strong>省了 draft 自回归那 k 步</strong></li><li>训练成本低(冻结 target,只训 Medusa 头,几小时到一天)</li></ul><p><strong>代价</strong>:</p><ul><li>每个头独立预测,<strong>头 i 的预测不依赖头 i-1 的输出</strong>,长程接受率低</li><li>实际把 k 个头展开成&quot;树状候选&quot;(Tree Attention),一次验证多个分支</li><li>接受率比 EAGLE 略低,但实现简单</li></ul><p>vLLM、TGI 都集成了 Medusa。</p><h3 id="_2-3-eagle-eagle-2-medusa-的改良-接受率更高" tabindex="-1">2.3 EAGLE / EAGLE-2:Medusa 的改良,接受率更高 <a class="header-anchor" href="#_2-3-eagle-eagle-2-medusa-的改良-接受率更高" aria-label="Permalink to &quot;2.3 EAGLE / EAGLE-2:Medusa 的改良,接受率更高&quot;">​</a></h3><p>Li et al. 2024(EAGLE)、2024(EAGLE-2)。Medusa 的弱点是头 i 看不到头 i-1 的猜测;EAGLE 加一个小的<strong>自回归 draft 网络</strong>,但这个 draft 网络:</p><ul><li>输入是 <strong>target 模型的 hidden state</strong>(不是 token embedding)——拿到的信息丰富得多</li><li>共享 target 的 LM head,词表分布天然对齐</li><li>自回归生成,但是在一个轻量化的 1-2 层 Transformer 上跑</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>target hidden state h_t</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>   EAGLE draft (轻量 Transformer)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>   ┌────┴────────┬────────┬────────┐</span></span>
<span class="line"><span>   ▼             ▼        ▼        ▼</span></span>
<span class="line"><span> next h_{t+1}  h_{t+2}   h_{t+3}  h_{t+4}</span></span>
<span class="line"><span>   │             │        │        │</span></span>
<span class="line"><span>   ▼             ▼        ▼        ▼</span></span>
<span class="line"><span>  LM Head (共享 target 的)</span></span>
<span class="line"><span>   │             │        │        │</span></span>
<span class="line"><span>   ▼             ▼        ▼        ▼</span></span>
<span class="line"><span>  token1        token2   token3   token4</span></span></code></pre></div><p>EAGLE-2 进一步引入<strong>动态草稿树</strong>:不是固定 k 步深度,而是根据每步的概率自适应展开(高概率分支多猜几步,低概率早停)。</p><p>接受率:EAGLE 60-70%、EAGLE-2 70-85%(代码 / 数学场景能到 85%+),目前是接受率最高的方案之一。</p><h3 id="_2-4-lookahead-decoding-不要-draft-模型-用-n-gram-表" tabindex="-1">2.4 Lookahead Decoding:不要 draft 模型,用 n-gram 表 <a class="header-anchor" href="#_2-4-lookahead-decoding-不要-draft-模型-用-n-gram-表" aria-label="Permalink to &quot;2.4 Lookahead Decoding:不要 draft 模型,用 n-gram 表&quot;">​</a></h3><p>Fu et al. 2024。完全无需任何额外训练:<strong>用 prompt 和已生成内容里的 n-gram 共现统计当 draft</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型已生成: &quot;def binary_search(arr, target):\\n    left, right = 0, len(arr)&quot;</span></span>
<span class="line"><span>                                                ↑</span></span>
<span class="line"><span>当前位置之后,n-gram 表里 &quot;0, len(arr)&quot; 之后高频出现 &quot;- 1&quot;。</span></span>
<span class="line"><span>拿 &quot;- 1&quot; 当 draft 候选,target 一次 forward 验证。</span></span></code></pre></div><p><strong>好处</strong>:零训练成本、零额外显存、立刻可用、code/数学场景接受率不低。 <strong>代价</strong>:开放领域 / 通用 chat 接受率偏低(没有结构化模式让 n-gram 学到);加速比不如 EAGLE。</p><h3 id="_2-5-一张对比表" tabindex="-1">2.5 一张对比表 <a class="header-anchor" href="#_2-5-一张对比表" aria-label="Permalink to &quot;2.5 一张对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>训练成本</th><th>推理额外开销</th><th>显存额外</th><th>典型加速比</th><th>接受率</th></tr></thead><tbody><tr><td><strong>Speculative (独立 draft)</strong></td><td>无(用现成小模型)</td><td>draft 自回归 k 步</td><td>draft 模型 + 它的 KV</td><td>1.5-2.5x</td><td>50-70%</td></tr><tr><td><strong>Medusa</strong></td><td>训 Medusa heads(数小时)</td><td>一次 forward 出 k 头</td><td>几亿参数的头</td><td>2-3x</td><td>50-65%</td></tr><tr><td><strong>EAGLE / EAGLE-2</strong></td><td>训 draft Transformer(1-2 天)</td><td>轻量 draft 自回归</td><td>几亿到 1B 的 draft</td><td>2.5-4x</td><td>70-85%</td></tr><tr><td><strong>Lookahead</strong></td><td>零</td><td>n-gram 表维护(很轻)</td><td>KB 级</td><td>1.3-2x</td><td>30-70%(任务依赖)</td></tr></tbody></table><p><strong>结论</strong>:</p><ul><li><strong>零成本试水</strong> → Lookahead</li><li><strong>想要最稳的加速</strong> → EAGLE-2(已经在 vLLM / SGLang / TRT-LLM 都进了)</li><li><strong>快速集成不想训练</strong> → Medusa(现成头权重也有发布)</li><li><strong>传统 speculative</strong> → 现在已经少用,被 Medusa / EAGLE 接替</li></ul><hr><h2 id="三、为什么大-batch-下投机收益会消失" tabindex="-1">三、为什么大 batch 下投机收益会消失 <a class="header-anchor" href="#三、为什么大-batch-下投机收益会消失" aria-label="Permalink to &quot;三、为什么大 batch 下投机收益会消失&quot;">​</a></h2><p>这是最重要也最容易被忽略的一点。</p><h3 id="_3-1-大-batch-已经把-decode-拖出-memory-bound-区" tabindex="-1">3.1 大 batch 已经把 decode 拖出 memory-bound 区 <a class="header-anchor" href="#_3-1-大-batch-已经把-decode-拖出-memory-bound-区" aria-label="Permalink to &quot;3.1 大 batch 已经把 decode 拖出 memory-bound 区&quot;">​</a></h3><p>回到 02 篇的 Roofline:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>decode batch=1:    算术强度 ≈ 2     远在拐点左侧,纯 memory-bound,算力空 95%</span></span>
<span class="line"><span>decode batch=32:   算术强度 ≈ 64    仍在左侧,但 SM 利用率已经到 30-50%</span></span>
<span class="line"><span>decode batch=256:  算术强度 ≈ 256   接近拐点,SM 利用率 70-90%</span></span></code></pre></div><p>batch=1 时投机解码&quot;白嫖&quot;算力的逻辑成立,因为算力本来就没用。 batch=256 时<strong>算力已经被并发请求填满了</strong>——你再塞 k 个候选进同一次 forward,Tensor Core 已经满负荷,投机解码不再&quot;免费&quot;,而是要真消耗算力。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>小 batch (1-8):     投机解码 ≈ &quot;搭便车&quot;,2-3x 加速,几乎纯赚</span></span>
<span class="line"><span>中 batch (16-64):   投机解码加速比缩水到 1.3-2x,看接受率</span></span>
<span class="line"><span>大 batch (128+):    投机解码可能 1.0x 甚至负优化——草稿开销 + 算力争抢</span></span></code></pre></div><h3 id="_3-2-工程上怎么选" tabindex="-1">3.2 工程上怎么选 <a class="header-anchor" href="#_3-2-工程上怎么选" aria-label="Permalink to &quot;3.2 工程上怎么选&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的服务 QPS / 并发是?</span></span>
<span class="line"><span>├── 低并发(单机 batch &lt; 8):</span></span>
<span class="line"><span>│   交互式 ChatBot、本地助手、code completion</span></span>
<span class="line"><span>│   → 上投机解码,EAGLE-2 是当前首选</span></span>
<span class="line"><span>├── 中并发(batch 16-64):</span></span>
<span class="line"><span>│   多用户 API 服务,但每用户 TPOT 仍重要</span></span>
<span class="line"><span>│   → 看 SLO。如果 TPOT 优先,上 EAGLE-2;吞吐优先,不上</span></span>
<span class="line"><span>└── 高并发(batch 128+):</span></span>
<span class="line"><span>    流量极大的公共 API</span></span>
<span class="line"><span>    → 别上,大 batch + Continuous Batching 已经是最优</span></span>
<span class="line"><span>    → 反而要思考分流:把 TPOT 敏感请求走 spec server,</span></span>
<span class="line"><span>      吞吐请求走普通 server(disaggregated serving)</span></span></code></pre></div><p><strong>这就是为什么 OpenAI / Anthropic 这种巨流量场景,投机解码不是默认开</strong>——他们的 batch 早就把算力打满了。中小流量的自部署服务才是投机解码的甜区。</p><hr><h2 id="四、接受率为什么任务依赖" tabindex="-1">四、接受率为什么任务依赖 <a class="header-anchor" href="#四、接受率为什么任务依赖" aria-label="Permalink to &quot;四、接受率为什么任务依赖&quot;">​</a></h2><h3 id="_4-1-高接受率任务" tabindex="-1">4.1 高接受率任务 <a class="header-anchor" href="#_4-1-高接受率任务" aria-label="Permalink to &quot;4.1 高接受率任务&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>代码:  &quot;for i in range(&quot; → &quot;len(&quot;   下一个 token 强烈可预测</span></span>
<span class="line"><span>数学:  &quot;因此, 答案是 &quot;  → 数字或公式 token 可预测</span></span>
<span class="line"><span>模板:  JSON / XML / 表格生成,大量结构 token 确定</span></span>
<span class="line"><span>重复:  &quot;上面的内容我再总结一下:&quot;  下一段往往复述前文,n-gram 命中高</span></span></code></pre></div><p>EAGLE-2 在 HumanEval / GSM8K 这些任务上接受率 80%+,加速 3-4x 实测可得。</p><h3 id="_4-2-低接受率任务" tabindex="-1">4.2 低接受率任务 <a class="header-anchor" href="#_4-2-低接受率任务" aria-label="Permalink to &quot;4.2 低接受率任务&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开放创作:  &quot;故事的下一段...&quot;     分布发散,小模型猜不准</span></span>
<span class="line"><span>长篇推理:  CoT 长链思考          每一步推理选择多,接受率掉</span></span>
<span class="line"><span>多语言切换: 中英文混合代码注释    draft 模型可能没学到这种切换</span></span>
<span class="line"><span>角色扮演:  奇幻 / 拟人 / 风格化   越偏离训练分布,接受率越低</span></span></code></pre></div><p>加速 1.2-1.5x 算正常,1.0x 不奇怪。<strong>上线前必须按业务真实流量跑 acceptance benchmark</strong>,别看论文数字就以为自己也能 3x。</p><h3 id="_4-3-如何监控接受率" tabindex="-1">4.3 如何监控接受率 <a class="header-anchor" href="#_4-3-如何监控接受率" aria-label="Permalink to &quot;4.3 如何监控接受率&quot;">​</a></h3><p>vLLM / SGLang 都暴露 <code>spec_token_acceptance_rate</code> 类指标:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平均接受率:    每轮接受 / 草稿 token 数 的滑动平均</span></span>
<span class="line"><span>分布尾部:      P10 接受率(差的请求烂到什么程度)</span></span>
<span class="line"><span>任务分桶:      按 prompt 类型(代码 / 数学 / 闲聊)分别看接受率</span></span></code></pre></div><p>阈值经验:<strong>&lt; 40% 整体接受率 → 关掉投机解码</strong>(草稿开销已经吃完收益)。</p><hr><h2 id="五、vllm-sglang-trt-llm-的支持现状-2026-视角" tabindex="-1">五、vLLM / SGLang / TRT-LLM 的支持现状(2026 视角) <a class="header-anchor" href="#五、vllm-sglang-trt-llm-的支持现状-2026-视角" aria-label="Permalink to &quot;五、vLLM / SGLang / TRT-LLM 的支持现状(2026 视角)&quot;">​</a></h2><h3 id="_5-1-vllm" tabindex="-1">5.1 vLLM <a class="header-anchor" href="#_5-1-vllm" aria-label="Permalink to &quot;5.1 vLLM&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动时加 spec config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vllm.entrypoints.openai.api_server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-llama/Meta-Llama-3.1-70B-Instruct</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-llama/Meta-Llama-3.2-1B-Instruct</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --num-speculative-tokens</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-draft-tensor-parallel-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><ul><li>支持:独立 draft、Medusa、EAGLE、Lookahead</li><li>配置成熟,文档齐全</li><li>默认不开,需要显式启</li></ul><h3 id="_5-2-sglang" tabindex="-1">5.2 SGLang <a class="header-anchor" href="#_5-2-sglang" aria-label="Permalink to &quot;5.2 SGLang&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sglang.launch_server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --model-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> meta-llama/Meta-Llama-3.1-70B-Instruct</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> EAGLE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-draft-model-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .../eagle-checkpoint</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-num-steps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-eagle-topk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --speculative-num-draft-tokens</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 64</span></span></code></pre></div><ul><li>支持:Medusa、EAGLE / EAGLE-2、Lookahead</li><li>跟 RadixAttention 协同好(共享前缀的请求在 spec 树上也能命中)</li><li>与结构化输出叠加效果显著(grammar 限制让接受率更高)</li></ul><h3 id="_5-3-tensorrt-llm" tabindex="-1">5.3 TensorRT-LLM <a class="header-anchor" href="#_5-3-tensorrt-llm" aria-label="Permalink to &quot;5.3 TensorRT-LLM&quot;">​</a></h3><ul><li>编译期就把 spec 决策 build 进 engine,运行时无 Python 开销</li><li>支持 Medusa、EAGLE、Lookahead、传统 spec</li><li>在 H100/H200 + FP8 上能把 spec 收益再压一档(算子更快 → 草稿验证开销更低)</li><li>代价:换 spec 算法 = 重 build engine,迭代慢</li></ul><hr><h2 id="六、踩坑提醒" tabindex="-1">六、踩坑提醒 <a class="header-anchor" href="#六、踩坑提醒" aria-label="Permalink to &quot;六、踩坑提醒&quot;">​</a></h2><ol><li><strong>接受率上线前必须 benchmark</strong>——论文数字基于学术 dataset,生产流量可能完全不同。</li><li><strong><code>num_speculative_tokens</code> 不是越大越好</strong>——典型 4-8 最佳。再大,接受率随位置衰减,后面几个白算。</li><li><strong>draft 模型必须同家族 + 同 tokenizer</strong>——Qwen draft 配 Llama target 不工作,词表不一样。</li><li><strong>温度高的采样接受率会降</strong>——temperature 1.0 + top_p 0.95 时,target 分布发散,draft 不容易撞中。code 任务用 temperature 0 接受率最高。</li><li><strong>多 LoRA 场景投机解码复杂</strong>——draft 模型也得知道当前用哪个 LoRA;目前主流引擎在 multi-LoRA + spec 的组合上还不够成熟。</li><li><strong>长上下文场景接受率会衰减</strong>——seq_len &gt; 32K 时,draft 模型未必被训过这么长,后段接受率掉。</li><li><strong>batch 自适应</strong>——成熟的引擎在 batch 大时自动关 spec 或减少 num_spec_tokens,看你用的引擎是不是开了这个开关。</li><li><strong>EAGLE 的 draft checkpoint 要单训</strong>——不同 target 对应不同 draft,不能跨模型复用。社区有 SpecBench / 公开 checkpoint 但模型覆盖有限。</li><li><strong>接受率监控放在 dashboard 第一屏</strong>——这玩意会因为流量分布漂移悄悄掉。</li><li><strong>不要拿 spec 解决 TTFT</strong>——spec 只加速 decode(出 token 阶段),prefill(首 token)那部分一点没省。</li></ol><hr><h2 id="七、和下一篇的连接" tabindex="-1">七、和下一篇的连接 <a class="header-anchor" href="#七、和下一篇的连接" aria-label="Permalink to &quot;七、和下一篇的连接&quot;">​</a></h2><p>投机解码是<strong>算法层</strong>的 decode 加速:在不改 GPU 硬件、不动模型权重的前提下,挖出 memory-bound 留下的算力空隙。</p><p>下一篇要讲的 TensorRT-LLM 是<strong>编译层 + Kernel 层</strong>的加速:它通过 AOT 编译、算子融合、FP8 落地等手段,把 decode 一次 forward 本身做得更快。两者<strong>正交</strong>——TRT-LLM 上叠加 EAGLE,理论收益相乘。生产部署里,<strong>TRT-LLM + EAGLE-2 + FP8</strong> 是目前 H100/H200 上单卡推理的极限组合。</p><hr><h2 id="八、看完这一篇-你应该能" tabindex="-1">八、看完这一篇,你应该能 <a class="header-anchor" href="#八、看完这一篇-你应该能" aria-label="Permalink to &quot;八、看完这一篇,你应该能&quot;">​</a></h2><ul><li>解释为什么 LLM decode 是 memory-bound,这是投机解码能成立的前提</li><li>默写朴素 decode vs 投机 decode 的时间线对比图</li><li>解释接受率(acceptance rate)为什么是关键指标,典型 70%+ 才有显著加速</li><li>默写四种流派(原始 spec / Medusa / EAGLE-2 / Lookahead)的区别和适用场景</li><li>解释为什么大 batch 下投机解码收益会消失(算力已被 Continuous Batching 填满)</li><li>看到一个推理需求,能判断该不该上投机解码、应该上哪种</li><li>知道线上必须监控接受率,&lt; 40% 就关</li></ul><p>下一篇:<strong>12 TensorRT-LLM 心智</strong> — NVIDIA 的编译式推理栈,把 PyTorch 模型 AOT 编译成 engine 二进制,在 H100/H200 上靠 FP8、算子融合、Plugin 系统压榨最后 20-50% 性能。代价是 engine 与 GPU 型号绑定、迭代成本高——什么时候它真比 vLLM 香,什么时候是过度工程。</p>`,90)])])}const k=s(p,[["render",i]]);export{g as __pageData,k as default};
